import fs from 'node:fs';
import path from 'node:path';
import { answersByDesignKey, QUESTIONNAIRE_SLIDES, validateCompleteAnswers } from './schema.mjs';

export const DESIGN_MD_FILENAME = 'DESIGN.md';
export const STAGED_DESIGN_MD_PATH = path.join('.impeccable', 'questionnaire', 'DESIGN.next.md');

export function buildDesignMd({
  answers,
  command = 'shape',
  prompt = '',
  product = '',
  generatedAt = new Date().toISOString(),
} = {}) {
  validateCompleteAnswers(answers);
  const keyed = answersByDesignKey(answers);
  const projectName = titleFromAnswer(keyed.projectIdentity?.value) || titleFromProduct(product) || 'Project';
  const siteOverview = sentence(keyed.siteOverview?.value);
  const tagline = siteOverview || 'Design direction captured through Impeccable shape discovery.';
  const colors = colorTokensForStrategy(keyed.colorStrategy?.value);
  const stateList = valueList(keyed.keyStates);
  const constraints = keyed.motionAccess?.value || 'WCAG AA, visible focus states, responsive layout, and reduced-motion alternatives.';
  const antiGoals = keyed.doDont?.value || 'Avoid generic AI-tool visual tropes and unclear interaction states.';

  return `---
name: ${yamlString(projectName)}
description: ${yamlString(tagline)}
colors:
  primary: "${colors.primary}"
  secondary: "${colors.secondary}"
  background: "${colors.background}"
  surface: "${colors.surface}"
  text: "${colors.text}"
typography:
  display:
    fontFamily: "system-ui, sans-serif"
    fontSize: "5.2rem"
    fontWeight: 650
    lineHeight: 1.04
    letterSpacing: "0"
  body:
    fontFamily: "system-ui, sans-serif"
    fontSize: "1rem"
    fontWeight: 400
    lineHeight: 1.7
rounded:
  sm: "4px"
  md: "8px"
spacing:
  sm: "8px"
  md: "16px"
  lg: "32px"
components:
  button-primary:
    backgroundColor: "{colors.primary}"
    textColor: "{colors.background}"
    rounded: "{rounded.sm}"
    padding: "14px 24px"
---

# Design System: ${projectName}

<!-- SEED: generated by Impeccable ${command} browser questionnaire at ${generatedAt}. Re-run /impeccable document after the interface exists to extract real tokens. -->

## 1. Overview

**Creative North Star: "${cleanInline(keyed.visualNorthStar?.value)}"**

${paragraph(keyed.projectIdentity?.value)} ${paragraph(keyed.siteOverview?.value)} The primary user is ${lowerFirst(paragraph(keyed.primaryUser?.value))} The first screen should make clear that ${lowerFirst(paragraph(keyed.success?.value))}

The surface should be designed from this scene: ${sentence(keyed.themeScene?.value)} The component posture is ${componentFeelLabel(keyed.componentFeel)}. The type should feel like ${lowerFirst(sentence(keyed.typographyVoice?.value))}

**Key Characteristics:**
- Site: ${siteOverview}
- User state: ${sentence(keyed.primaryUser?.value)}
- First-screen clarity: ${sentence(keyed.success?.value)}
- Content/data: ${sentence(keyed.contentData?.value)}
- Required states: ${stateList || 'default, mobile, error, and success'}

## 2. Colors

Use a ${colorStrategyLabel(keyed.colorStrategy)} strategy. Color should support the scene, not decorate around it.

### Primary
- **Primary** (${colors.primary}): The main commitment color for primary actions, active states, and the strongest brand signal.

### Secondary
- **Secondary** (${colors.secondary}): The state and contrast color for progress, confirmation, hover emphasis, and secondary affordances.

### Neutral
- **Background** (${colors.background}): The page ground.
- **Surface** (${colors.surface}): Raised or grouped UI areas.
- **Text** (${colors.text}): Primary reading color.

### Named Rules
**The Color Strategy Rule.** Keep the selected color strategy visible in the first viewport and in every primary action.

## 3. Typography

**Display Font:** system-ui, sans-serif
**Body Font:** system-ui, sans-serif

**Character:** ${sentence(keyed.typographyVoice?.value)}

### Hierarchy
- **Display** (650, 5.2rem, 1.04): Hero headlines and major commitments only.
- **Headline** (600, 3rem, 1.12): Section anchors and question-level decisions.
- **Title** (560, 1.15rem, 1.35): Component and panel titles.
- **Body** (400, 1rem, 1.7): Explanatory copy, capped at 65-75ch.
- **Label** (600, 0.8rem, 0.08em): Short system labels only.

### Named Rules
**The Specific Type Rule.** Type choices should express the physical reference above; do not fall back to generic "clean" typography without a reason.

## 4. Elevation

Use elevation only when it clarifies interaction or hierarchy. Default surfaces should rely on tonal contrast, spacing, borders, and focus treatment before shadow.

### Shadow Vocabulary
- **Interactive lift** (\`0 8px 24px rgba(0, 0, 0, 0.14)\`): Use only on active hover or draggable surfaces.
- **Modal setback** (\`0 24px 64px rgba(0, 0, 0, 0.22)\`): Use for blocking overlays when the product needs them.

### Named Rules
**The State-First Rule.** Elevation appears as feedback or focus, not as decoration on every container.

## 5. Components

### Buttons
- **Shape:** Small radius (4px) unless the product already has a sharper token.
- **Primary:** Primary color fill, background-colored text, clear verb-object label.
- **Hover / Focus:** State change must be visible by color or outline; focus uses a high-contrast outline offset from the control.
- **Secondary / Ghost:** Keep secondary actions quieter than the primary action.

### Cards / Containers
- **Corner Style:** Small radius, no nested cards.
- **Background:** Use the surface token with clear spacing and a single grouping mechanism.
- **Shadow Strategy:** Follow the Elevation section.
- **Internal Padding:** Start from 16px to 32px and adjust by density.

### Inputs / Fields
- **Style:** Visible label, clear border or fill, no placeholder-only labels.
- **Focus:** Border or outline shift strong enough for keyboard users.
- **Error / Disabled:** Error text names the fix. Disabled state remains readable.

### Navigation
- **Style:** Keep current location and next action obvious. Mobile navigation must preserve the primary action.

### Signature Surface
${sentence(keyed.contentData?.value)} Design this as real content with edge cases, not placeholder blocks.

## 6. Do's and Don'ts

### Do:
- **Do** design for this user context: ${sentence(keyed.primaryUser?.value)}
- **Do** handle these states: ${stateList || 'default, mobile, error, loading, and success'}.
- **Do** preserve accessibility constraints: ${sentence(constraints)}

### Don't:
- **Don't** ignore this anti-goal: ${sentence(antiGoals)}
- **Don't** use generic AI-tool tropes when the surface needs a specific product voice.
- **Don't** hide real content, limits, errors, or user consequences behind decorative layout.
`;
}

export function resolveDesignWriteTarget(cwd = process.cwd()) {
  const designPath = path.join(cwd, DESIGN_MD_FILENAME);
  if (fs.existsSync(designPath)) {
    return {
      targetPath: STAGED_DESIGN_MD_PATH,
      absolutePath: path.join(cwd, STAGED_DESIGN_MD_PATH),
      existingDesign: true,
      action: 'staged',
    };
  }
  return {
    targetPath: DESIGN_MD_FILENAME,
    absolutePath: designPath,
    existingDesign: false,
    action: 'written',
  };
}

export function writeDesignMd({ cwd = process.cwd(), designMd }) {
  const target = resolveDesignWriteTarget(cwd);
  fs.mkdirSync(path.dirname(target.absolutePath), { recursive: true });
  fs.writeFileSync(target.absolutePath, designMd);
  return target;
}

export function slideSummary(answers = {}) {
  return QUESTIONNAIRE_SLIDES
    .map((slide) => {
      const answer = answers[slide.id];
      if (!answer) return null;
      return { id: slide.id, title: slide.title, label: answer.label, value: answer.value };
    })
    .filter(Boolean);
}

function colorTokensForStrategy(strategy) {
  if (strategy === 'drenched') {
    return {
      primary: '#b8902f',
      secondary: '#2f8f88',
      background: '#17140d',
      surface: '#211d14',
      text: '#f3f0e8',
    };
  }
  if (strategy === 'full-palette') {
    return {
      primary: '#b8902f',
      secondary: '#2f8f88',
      background: '#111111',
      surface: '#1c1c1c',
      text: '#f2f2f2',
    };
  }
  if (strategy === 'committed') {
    return {
      primary: '#b8902f',
      secondary: '#2f8f88',
      background: '#10100e',
      surface: '#191916',
      text: '#f0f0ec',
    };
  }
  return {
    primary: '#b8902f',
    secondary: '#2f8f88',
    background: '#111111',
    surface: '#1a1a1a',
    text: '#f0f0f0',
  };
}

function titleFromAnswer(value) {
  if (!value) return '';
  const first = String(value).split(/[.;:]/)[0].trim();
  return first.length > 72 ? first.slice(0, 69).trim() + '...' : first;
}

function titleFromProduct(product = '') {
  const match = String(product).match(/^#\s+(.+)$/m);
  return match ? match[1].trim() : '';
}

function yamlString(value) {
  return JSON.stringify(String(value || '').replace(/\s+/g, ' ').trim());
}

function sentence(value) {
  const text = cleanInline(value);
  if (!text) return '';
  return /[.!?]$/.test(text) ? text : `${text}.`;
}

function paragraph(value) {
  return sentence(value);
}

function cleanInline(value) {
  if (value && typeof value === 'object' && 'value' in value) return cleanInline(value.value);
  if (Array.isArray(value)) return value.join(', ');
  return String(value || '').replace(/\s+/g, ' ').trim();
}

function lowerFirst(value) {
  const text = String(value || '').trim();
  return text ? text.charAt(0).toLowerCase() + text.slice(1) : '';
}

function valueList(answer) {
  if (!answer) return '';
  if (Array.isArray(answer.value)) return answer.label || answer.value.join(', ');
  return answer.label || answer.value || '';
}

function colorStrategyLabel(answer) {
  return answer?.label || answer?.value || 'Restrained';
}

function componentFeelLabel(answer) {
  return answer?.label ? answer.label.toLowerCase() : 'quiet and precise';
}
